import React, { useCallback } from 'react';
import { hasPermissionCode, usePeriodJobPermissions } from '../../../hooks/usePeriodJobPermissions';
import { PeriodActionPanel } from '../../../components/kt/PeriodActionPanel';
import { ktService } from '../../../services/kt/ktService';
import { PERIOD_JOB_TYPES } from '../../../constants/periodJobTypes';
import { PERIOD_REFERENCE_NO } from '../../../constants/periodProcessReferences';
import { periodProcessStatusLabel } from '../../../utils/periodProcessStatusLabel';

const PhanBoCcdcPage: React.FC = () => {
  const { canRun, canPost } = usePeriodJobPermissions('tools-allocation');
  void hasPermissionCode;
  const getStatus = useCallback(
    async (m: number, y: number) => periodProcessStatusLabel(await ktService.getToolsAllocationStatus(m, y)),
    [],
  );

  return (
    <PeriodActionPanel
      testIdPrefix="kt-phan-bo-ccdc"
      title="Phân bổ CCDC"
      icon="fa-tools"
      runLabel="Phân bổ"
      postLabel="Ghi sổ"
      jobType={PERIOD_JOB_TYPES.ToolsAllocation}
      referenceNo={PERIOD_REFERENCE_NO.Tools}
      getStatus={getStatus}
      onRun={(m, y) => ktService.runToolsAllocation(m, y)}
      onPost={(m, y) => ktService.postToolsAllocation(m, y)}
      runPermitted={canRun}
      postPermitted={canPost}
    />
  );
};

export default PhanBoCcdcPage;
